# ?????????????????????????????????????????????????????????????????????????????
# Helper: replace a flat list of [old,new] pairs inside a file
# ?????????????????????????????????????????????????????????????????????????????
function Clean-File {
    param([string]$path, [string[][]]$pairs)
    $c = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)
    foreach ($p in $pairs) {
        $c = $c.Replace($p[0], $p[1])
    }
    [System.IO.File]::WriteAllText($path, $c, [System.Text.Encoding]::UTF8)
    Write-Host "Cleaned: $([System.IO.Path]::GetFileName($path))"
}

